// THEME
function toggleTheme() {
  const isDark = !document.documentElement.getAttribute('data-theme');
  document.documentElement.setAttribute('data-theme', isDark ? 'light' : '');
  document.querySelector('.theme-toggle').textContent = isDark ? '◐' : '☀';
}

// COUNTERS
function animateCounters() {
  document.querySelectorAll('.counter').forEach(el => {
    const target = +el.dataset.target;
    const dur = 1400;
    const start = performance.now();
    function step(now) {
      const p = Math.min((now - start) / dur, 1);
      const ease = 1 - Math.pow(1 - p, 3);
      el.textContent = Math.round(ease * target);
      if (p < 1) requestAnimationFrame(step);
    }
    requestAnimationFrame(step);
  });
}
const statsObs = new IntersectionObserver(entries => {
  if (entries[0].isIntersecting) { animateCounters(); statsObs.disconnect(); }
}, { threshold: 0.5 });
statsObs.observe(document.querySelector('.stats-bar'));

// SCROLL FADE
const fadeObs = new IntersectionObserver(entries => {
  entries.forEach(e => { if (e.isIntersecting) e.target.classList.add('visible'); });
}, { threshold: 0.12 });
document.querySelectorAll('.fade-in').forEach(el => fadeObs.observe(el));

// SKILLS GRID ANIMATION
const skills = [
  { word: 'REACT',      full: 'React.js' },
  { word: 'NATIVE',     full: 'React Native' },
  { word: 'NEXTJS',     full: 'Next.js' },
  { word: 'TYPESCRIPT', full: 'TypeScript' },
  { word: 'JAVASCRIPT', full: 'JavaScript' },
  { word: 'NODEJS',     full: 'Node.js' },
  { word: 'REDUX',      full: 'Redux' },
  { word: 'ZUSTAND',    full: 'Zustand' },
  { word: 'GIT',        full: 'Git' },
  { word: 'RESTAPI',    full: 'REST API' },
  { word: 'HTML5',      full: 'HTML5' },
  { word: 'CSS3',       full: 'CSS3' },
];

const SCRAMBLE_SPEED = 240;   // ms per frame
const REVEAL_LETTER_DELAY = 160; // ms per letter
const HOLD_TIME = 4500;        // how long word is shown
const COLLAPSE_SCRAMBLE = 220;
const CYCLE_BASE = 7000;       // ms between cycles per row

function buildSkillGrid() {
  const container = document.getElementById('skillsGrid');
  const cellW = 48;
  const cols = Math.floor(window.innerWidth / cellW);
  container.innerHTML = '';
  const allRows = [];

  for (let r = 0; r < skills.length; r++) {
    const row = document.createElement('div');
    row.className = 'skill-row';
    const cells = [];
    const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789';
    for (let c = 0; c < cols; c++) {
      const cell = document.createElement('div');
      cell.className = 'skill-cell';
      cell.textContent = chars[Math.floor(Math.random() * chars.length)];
      row.appendChild(cell);
      cells.push(cell);
    }
    container.appendChild(row);
    allRows.push({ cells, word: skills[r].word, full: skills[r].full });
  }

  allRows.forEach(({ cells, word }, ri) => {
    const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789';
    const wordStart = Math.floor((cells.length - word.length) / 2);
    let revealed = false;

    function randomChar() { return chars[Math.floor(Math.random() * chars.length)]; }

    function scramble(interval) {
      return setInterval(() => {
        if (!revealed) cells.forEach(cell => { cell.textContent = randomChar(); cell.classList.remove('lit','bright'); });
      }, interval);
    }

    function revealWord(cb) {
      revealed = true;
      cells.forEach((cell, ci) => {
        const inWord = ci >= wordStart && ci < wordStart + word.length;
        const delay = inWord ? (ci - wordStart) * REVEAL_LETTER_DELAY : 0;
        setTimeout(() => {
          if (inWord) { cell.textContent = word[ci - wordStart]; cell.classList.add('bright'); }
          else { cell.classList.add('lit'); cell.textContent = randomChar(); }
        }, delay);
      });
      if (cb) setTimeout(cb, word.length * REVEAL_LETTER_DELAY + HOLD_TIME);
    }

    function collapseWord(cb) {
      revealed = false;
      cells.forEach(cell => { cell.classList.remove('lit','bright'); cell.textContent = randomChar(); });
      if (cb) setTimeout(cb, 300);
    }

    function runCycle() {
      const si = scramble(SCRAMBLE_SPEED);
      setTimeout(() => {
        clearInterval(si);
        revealWord(() => {
          collapseWord(() => {
            const si2 = scramble(COLLAPSE_SCRAMBLE);
            setTimeout(() => {
              clearInterval(si2);
              runCycle();
            }, 800);
          });
        });
      }, 900 + ri * 120);
    }

    // Stagger start per row
    setTimeout(runCycle, ri * 350);
  });
}


// Inject project screenshots
(function() {
  var imgs = {
  'thumb-fur': 'data:image/webp;base64,',
  'thumb-surf': 'data:image/webp;base64,',
    'thumb-cp': 'data:image/webp;base64,',
    'thumb-ft': 'data:image/webp;base64,',
    'thumb-tea': 'data:image/webp;base64,'
  };
  Object.entries(imgs).forEach(function([id, src]) {
    var thumb = document.getElementById(id);
    if (!thumb) return;
    var img = document.createElement('img');
    img.src = src;
    img.alt = id;
    img.style.cssText = 'width:100%;height:100%;object-fit:cover;object-position:top;display:block;transition:transform 0.4s ease;';
    thumb.insertBefore(img, thumb.firstChild);
    thumb.closest('.project-card').addEventListener('mouseenter', function() { img.style.transform='scale(1.03)'; });
    thumb.closest('.project-card').addEventListener('mouseleave', function() { img.style.transform=''; });
  });
})();

buildSkillGrid();
window.addEventListener('resize', () => {
  clearTimeout(window._rzt);
  window._rzt = setTimeout(buildSkillGrid, 200);
});

// CURSOR GLOW
const glow = document.getElementById('cursorGlow');
document.addEventListener('mousemove', e => {
  glow.style.left = e.clientX + 'px';
  glow.style.top = e.clientY + 'px';
});

// BURGER MENU
const burger = document.getElementById('navBurger');
const drawer = document.getElementById('navDrawer');
burger.addEventListener('click', () => {
  const isOpen = drawer.classList.toggle('open');
  burger.classList.toggle('open', isOpen);
  document.body.style.overflow = isOpen ? 'hidden' : '';
});
drawer.querySelectorAll('a').forEach(link => {
  link.addEventListener('click', () => {
    drawer.classList.remove('open');
    burger.classList.remove('open');
    document.body.style.overflow = '';
  });
});
